exercises.solutionCode:
function selectTool(goal) {
  const normalized = goal.toLowerCase();
  if (normalized.includes("find") || normalized.includes("latest") || normalized.includes("search")) return "search";
  if (normalized.includes("calculate") || normalized.includes("cost")) return "calculator";
  if (normalized.includes("remember") || normalized.includes("preferred")) return "memory";
  return "final";
}
